var minimumAverageDifference = function(nums) {
    const n = nums.length;
    let total = 0n;
    for (const x of nums) total += BigInt(x);
    let prefix = 0n;
    let bestIdx = 0;
    let bestVal = null;
    for (let i = 0; i < n; i++) {
        prefix += BigInt(nums[i]);
        const la = prefix / BigInt(i + 1);
        const rem = n - i - 1;
        const ra = rem ? (total - prefix) / BigInt(rem) : 0n;
        let d = la - ra;
        if (d < 0n) d = -d;
        if (bestVal === null || d < bestVal) {
            bestVal = d;
            bestIdx = i;
        }
    }
    return bestIdx;
};
